// Extract primary media URL and type from each ad
const items = $input.all();
const results = [];

for (const item of items) {
  const ad = item.json;
  const snapshot = ad.snapshot || {};
  const displayFormat = (snapshot.displayFormat || '').toUpperCase();

  let primaryMediaUrl = null;
  let mediaType = null;
  let mediaFileExtension = null;

  if (displayFormat === 'VIDEO') {
    // Video ads: grab from snapshot.videos[]
    const video = (snapshot.videos || [])[0];
    if (video) {
      primaryMediaUrl = video.videoHdUrl || video.videoSdUrl || null;
      mediaType = 'video';
      mediaFileExtension = 'mp4';
    }
  } else if (displayFormat === 'IMAGE') {
    // Image ads: grab from snapshot.images[]
    const image = (snapshot.images || [])[0];
    if (image) {
      primaryMediaUrl = image.originalImageUrl || image.resizedImageUrl || null;
      mediaType = 'image';
      mediaFileExtension = 'jpg';
    }
  } else if (displayFormat === 'CAROUSEL' || displayFormat === 'DCO') {
    // Carousel/DCO ads: grab first card image
    const card = (snapshot.cards || [])[0];
    if (card) {
      primaryMediaUrl = card.originalImageUrl || card.resizedImageUrl || null;
      mediaType = 'image';
      mediaFileExtension = 'jpg';
    }
  } else {
    // Fallback: check cards, then images, then videos
    const card = (snapshot.cards || [])[0];
    const image = (snapshot.images || [])[0];
    const video = (snapshot.videos || [])[0];

    if (card && (card.originalImageUrl || card.resizedImageUrl)) {
      primaryMediaUrl = card.originalImageUrl || card.resizedImageUrl;
      mediaType = 'image';
      mediaFileExtension = 'jpg';
    } else if (image && (image.originalImageUrl || image.resizedImageUrl)) {
      primaryMediaUrl = image.originalImageUrl || image.resizedImageUrl;
      mediaType = 'image';
      mediaFileExtension = 'jpg';
    } else if (video && (video.videoHdUrl || video.videoSdUrl)) {
      primaryMediaUrl = video.videoHdUrl || video.videoSdUrl;
      mediaType = 'video';
      mediaFileExtension = 'mp4';
    }
  }

  results.push({
    json: {
      ...ad,
      primaryMediaUrl,
      mediaType,
      mediaFileExtension,
      displayFormat
    }
  });
}

return results;

const crypto = require('crypto');
const items = $input.all();
const mediaList = [];
const seen = new Set();

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary?.data;
  const ad = $('extract_primary_media').all()[i]?.json;

  if (bin) {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const hash = crypto.createHash('md5').update(buffer).digest('hex');

    if (!seen.has(hash)) {
      seen.add(hash);
      mediaList.push({
        mimeType: ad?.mediaType === 'video' ? 'video/mp4' : 'image/jpeg',
        base64: buffer.toString('base64')
      });
    }
  }
}

return [{ json: { mediaList, totalItems: mediaList.length, deduped: items.length - mediaList.length } }];
